+/// AAC-P6 regenerative-renewal micro-batch state (ceremony amortization).
+///
+/// Caches the ceremony fingerprint of the most recent prepared-statement
+/// execution so that consecutive identical calls can skip the cached pieces.
+/// The amortized cost per row is (fixed_ceremony + variable_per_row) / N
+/// where N is the number of consecutive calls that share one epoch.
+///
+/// Consecutive-call identity is defined by the tuple:
+///   (stmt.program pointer, param count, schema_cookie, schema_generation,
+///    function_registry_generation, txn_epoch, concurrent_session_id).
+/// Any mismatch on the next call triggers a renewal (flush) — the state is
+/// rebuilt from scratch and the ceremony runs normally.
+#[derive(Debug, Clone)]
+struct StmtMicrobatchState {
+    /// Stable identity of the prepared statement: address of the `Arc`-owned
+    /// VDBE program, compared but never dereferenced.
+    program_ptr: usize,
+    /// Number of bound parameters at the previous call. The micro-batcher
+    /// treats a differing arity as a hard shape change and renews.
+    binds_arity: usize,
+    /// Schema cookie cached at state creation. Renewed on mismatch.
+    schema_cookie: u32,
+    /// Connection-local schema generation marker.
+    schema_generation: u64,
+    /// Function-registry generation marker.
+    function_registry_generation: u64,
+    /// Whether the current epoch is an explicit-transaction in-txn epoch.
+    in_explicit_txn: bool,
+    /// Current concurrent-session id (when the owning txn is MVCC-concurrent).
+    concurrent_session_id: Option<u64>,
+    /// Number of consecutive calls that have reused this epoch so far.
+    rows_accumulated: u32,
+    /// Absolute deadline (wall clock). Once passed, the next call renews.
+    deadline: Instant,
+}
