+    ///
+    /// Renewal-amortization note: `Instant::now()` on Linux is ~10–30 ns and
+    /// can easily dominate the very schema-validation work we are trying to
+    /// amortize. The wall-clock deadline is therefore sampled lazily — we
+    /// only consult `Instant::now()` once the row counter reaches a cheap
+    /// probe threshold, and only on the renewal path. This preserves the
+    /// staleness guarantee (max_us caps how long a single epoch can persist
+    /// before the next call re-verifies the cached ceremony) while keeping
+    /// the hit path free of syscalls.
+    fn stmt_microbatch_try_carry(
+        &self,
+        program_ptr: usize,
+        binds_arity: usize,
+        in_explicit_txn: bool,
+        concurrent_session_id: Option<u64>,
+    ) -> bool {
+        if !self.stmt_microbatch_is_enabled() {
+            return false;
+        }
+        let max_r = self.stmt_microbatch_max_r.get();
+        if max_r == 0 {
+            return false;
+        }
+        let schema_cookie = *self.schema_cookie.borrow();
+        let schema_generation = self.schema_generation.get();
+        let function_registry_generation = self.function_registry_generation.get();
+        // Fast hit-check path: single borrow_mut, no syscalls, no allocations.
+        {
+            let mut slot = self.stmt_microbatch_state.borrow_mut();
+            if let Some(state) = slot.as_mut() {
+                let identity_match = state.program_ptr == program_ptr
+                    && state.binds_arity == binds_arity
+                    && state.schema_cookie == schema_cookie
+                    && state.schema_generation == schema_generation
+                    && state.function_registry_generation == function_registry_generation
+                    && state.in_explicit_txn == in_explicit_txn
+                    && state.concurrent_session_id == concurrent_session_id
+                    && state.rows_accumulated < max_r;
