+            program_ptr,
+            binds_arity,
+            schema_cookie,
+            schema_generation,
+            function_registry_generation,
+            in_explicit_txn,
+            concurrent_session_id,
+            rows_accumulated: 1,
+            deadline,
+        });
+        self.stmt_microbatch_renewals
